query:
query RealmQuery(
  $path: String!
) {
  ...UserData
  currentUser {
    userRealmHandle
    canCreateUserRealm
  }
  realm: realmByPath(path: $path) {
    name
    path
    isMainRoot
    isUserRealm
    ownerDisplayName
    canCurrentUserModerate
    ancestors {
      name
      path
      ownerDisplayName
      id
    }
    ...BlocksData
    ...NavigationData
    id
  }
}

fragment BlocksBlockData on Block {
  __isBlock: __typename
  id
  __typename
  ... on TitleBlock {
    ...TitleBlockData
  }
  ... on TextBlock {
    ...TextBlockData
  }
  ... on SeriesBlock {
    ...SeriesBlockData
  }
  ... on VideoBlock {
    ...VideoBlockData
  }
  ... on PlaylistBlock {
    ...PlaylistBlockData
  }
}

fragment BlocksData on Realm {
  ...BlocksRealmData
  blocks {
    __typename
    id
    ...BlocksBlockData
  }
}

fragment BlocksRealmData on Realm {
  path
}

fragment NavigationData on Realm {
  id
  name
  path
  nav {
    header {
      name
      path
    }
    list {
      name
      path
      hasChildren
    }
    listOrder
  }
}

fragment PlaylistBlockData on PlaylistBlock {
  playlist {
    __typename
    ...PlaylistBlockPlaylistData
    ... on Node {
      __isNode: __typename
      id
    }
  }
  showTitle
  showMetadata
  order
  layout
}

fragment PlaylistBlockPlaylistData on Playlist {
  __isPlaylist: __typename
  __typename
  ... on NotAllowed {
    dummy
  }
  ... on AuthorizedPlaylist {
    id
    title
    description
    creator
    canWrite
    entries {
      __typename
      ... on AuthorizedEvent {
        id
        ...VideoListEventData
      }
      ... on Missing {
        dummy
      }
      ... on NotAllowed {
        dummy
      }
      ... on Node {
        __isNode: __typename
        id
      }
    }
  }
}

fragment SeriesBlockData on SeriesBlock {
  series {
    ...SeriesBlockSeriesData
    id
  }
  showTitle
  showMetadata
  order
  layout
}

fragment SeriesBlockSeriesData on Series {
  id
  title
  created
  description
  state
  metadata
  canWrite
  entries {
    __typename
    ... on AuthorizedEvent {
      id
      ...VideoListEventData
    }
    ... on NotAllowed {
      dummy
    }
    ... on Node {
      __isNode: __typename
      id
    }
  }
}

fragment TextBlockData on TextBlock {
  content
}

fragment TitleBlockData on TitleBlock {
  content
}

fragment UserData on Query {
  currentUser {
    username
    displayName
    userRealmHandle
    canUpload
    canUseStudio
    canUseEditor
    canCreateUserRealm
    canCreateSeries
    canCreatePlaylists
    isTobiraAdmin
    canFindUnlisted
    roles
    userRole
  }
}

fragment VideoBlockData on VideoBlock {
  event {
    __typename
    ... on NotAllowed {
      dummy
    }
    ... on AuthorizedEvent {
      id
      title
      isLive
      opencastId
      created
      creators
      metadata
      description
      canWrite
      hasPassword
      series {
        title
        id
        opencastId
      }
      syncedData {
        duration
        updated
        startTime
        endTime
        thumbnail
      }
      ...VideoPageAuthorizedData
    }
    ... on Node {
      __isNode: __typename
      id
    }
  }
  showTitle
  showLink
}

fragment VideoListEventData on AuthorizedEvent {
  id
  title
  created
  creators
  isLive
  description
  series {
    title
    id
  }
  syncedData {
    thumbnail
    duration
    startTime
    endTime
    audioOnly
  }
}

fragment VideoPageAuthorizedData on AuthorizedEvent {
  authorizedData {
    tracks {
      uri
      flavor
      mimetype
      resolution
      isMaster
    }
    captions {
      uri
      lang
    }
    segments {
      uri
      startTime
    }
  }
  id
}
